con:config.script:
import se.skl.rivta.testsupport.soapui.datasource.XmlDataReader
import com.eviware.soapui.support.GroovyUtils

def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")
def source = new XmlDataReader(context, dataFile)

source.load(testRunner.testCase.getName())

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

context.allRecords = ca.getContentRecords()

con:config.script:
def analysistime = '/urn:laboratoryOrderOutcome/urn1:body/urn1:groupOfAnalyses/urn1:analysis/urn1:specimen/urn1:timestamp'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.dates) {
	def analysistimes = context.allRecords.collect { record -> record.allElementsAt(analysistime) }.flatten()

	context.dates = (analysistimes).findAll().collect { it[0..7] }.unique()
	if (!context.dates) {
		testRunner.fail("No data")
	}
}

context.timePeriodStart = context.dates.pop()
context.timePeriodEnd = context.timePeriodStart
//log.info ([context.timePeriodStart, context.timePeriodEnd])

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

//Initiering
def requestStartFilled = context.timePeriodStart + '000000'
def requestEndFilled = context.timePeriodEnd + '235959'

def analysistime = '/urn:laboratoryOrderOutcome/urn1:body/urn1:groupOfAnalyses/urn1:analysis/urn1:specimen/urn1:timestamp'
def id = '/urn:laboratoryOrderOutcome/urn1:header/urn1:record/urn1:id/urn1:extension'
//log.info context.timePeriodStart + " : " + context.timePeriodEnd

def condition = { record -> 
	def analysisTimeWithin = record.allElementsAt(analysistime).any {it >= requestStartFilled && it <= requestEndFilled}
	return (analysisTimeWithin)
}

def recordInfo = { record ->
	sprintf("DocumentId %s (analysistime:%s)", [id, analysistime].collect{record.allElementsAt(it)})
}

ca.assertFilteredResponse(context.allRecords, condition, recordInfo)

con:config.script:
if (context.dates.any()) {
	testRunner.gotoStepByName( "Calculate interval")
}
else if (testRunner.getResults().any{it.getStatus().toString() == 'FAILED'}) {
	testRunner.fail("One or more steps failed")
}

