// create groovyUtils and XmlHolder for response of Request 1 request
def groovyUtils = new com.eviware.soapui.support.GroovyUtils( context )
def holder = groovyUtils.getXmlHolder( "Call GetLaboratoryOrderOutcome 1#Response" )
def path = testRunner.testCase.testSuite.project.getPropertyValue("RecordElementPath")
holder.declareNamespace("urn", "urn:riv:clinicalprocess:healthcond:actoutcome:GetLaboratoryOrderOutcomeResponder:4")
holder.declareNamespace("urn1", "urn:riv:clinicalprocess:healthcond:actoutcome:4")

//log.info path

def numberOfposts = holder["count(${path})"]
context.testCase.setPropertyValue("Poster request 1",numberOfposts)
//log.info numberOfposts

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
