con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

// create groovyUtils and XmlHolder for response of Request 1 request
def groovyUtils = new com.eviware.soapui.support.GroovyUtils( context )
def holder = groovyUtils.getXmlHolder( "Call GetLaboratoryOrderOutcome#Response" )

//Läs in respons och omvandla tecken
def xml = holder.getXml()
def unescapedXml = xml.replaceAll(/&amp;/, '&')
				.replaceAll(/&lt;/, '<')
         			.replaceAll(/&gt;/, '>')
         			.replaceAll(/&quot;/, '"')
         			.replaceAll(/&apos;/, "'")

//Läs in teststrängen och omvandla tecken
def testString = context.testString
def unescapedTestString = testString.replaceAll(/&amp;/, '&')
				.replaceAll(/&lt;/, '<')
         			.replaceAll(/&gt;/, '>')
         			.replaceAll(/&quot;/, '"')
         			.replaceAll(/&apos;/, "'")

assert unescapedXml.indexOf(unescapedTestString) > -1 : "Söksträngen " + unescapedTestString + " finns inte"

