con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

def signatureId = '/urn:laboratoryOrderOutcome/urn1:body/urn1:groupOfAnalyses/urn1:analysis/urn1:result/urn1:recipientSignature/urn1:id/urn1:extension'
def timestamp = '/urn:laboratoryOrderOutcome/urn1:body/urn1:groupOfAnalyses/urn1:analysis/urn1:result/urn1:recipientSignature/urn1:timestamp'

def condition = { record ->
	def hasSignatureId = record.allElementsAt(signatureId)
	def hasTimestamp = record.allElementsAt(timestamp)
	return hasSignatureId && hasTimestamp
}

def recordInfo = sprintf("Svaret innehåller ingen signerad post, dvs där signatur och signeringstidpunkt finns.")
ca.assertForAnyRecord(condition, recordInfo)

