def lvlLow = 'urn:laboratoryOrderOutcome/urn1:body/urn1:groupOfAnalyses/urn1:analysis/urn1:result/urn1:value/urn1:intervalPQ/urn1:low'
def lvlHigh = 'urn:laboratoryOrderOutcome/urn1:body/urn1:groupOfAnalyses/urn1:analysis/urn1:result/urn1:value/urn1:intervalPQ/urn1:high'

def condition = { record ->
    def lLow = record.firstElementAt(lvlLow)
    def lHigh = record.firstElementAt(lvlHigh)
    log.info( "haslvlLow: " + lLow)
    log.info( "hsalvlHigh: " + lHigh)    
    return lLow || lHigh
}

